INSERT INTO suspects (id, name, surname, gender, age, job, hobby, bad_habit, foot_size, hair_color, biography, image_url) VALUES
('a1b2c3d4-0001-4000-8000-000000000001', 'Oliver', 'Smith', 'male', 34, 'Engineer', 'Reading', 'Smoking', 42, 'Brown', 'Oliver Smith працює інженером у великій компанії вже понад десять років. Народився в Лідсі, навчався в Манчестері на факультеті машинобудування. Завжди любив техніку та головоломки, у вільний час збирав радіоприлади. Останнім часом мав серйозні фінансові проблеми через борги та розлучення. Колеги описують його як замкнутого, але доброзичливого чоловіка.', '/suspects/oliver.jpg'),
('a1b2c3d4-0002-4000-8000-000000000002', 'Anna', 'Johnson', 'female', 28, 'Doctor', 'Photography', 'Nail Biting', 38, 'Blonde', 'Анна Джонсон — лікарка-терапевт у місцевій клініці, закінчила медичний університет з відзнакою. Відома своїм холодним спокоєм та вмінням не піддаватися емоціям. Мала конфлікт з кількома колегами через різні методи лікування та підходи до пацієнтів. Займається фотографією, неодноразово виставляла роботи в галереях. У минулому році проходила стажування в тому ж закладі, де трапилася подія.', '/suspects/anna.jpg'),
('a1b2c3d4-0003-4000-8000-000000000003', 'William', 'Kovalski', 'male', 52, 'Chef', 'Cooking', 'Drinking', 44, 'Brown', 'Вільям Ковальскі — шеф-кухар у ресторані "Золота сковорода" більше двадцяти років. Працює з ножами та кухонним інвентарем щодня, має репутацію перфекціоніста. Мав особисту ворожнечу з жертвою через старий борг і публічну образу на кулінарному конкурсі. У минулому мав проблеми з алкоголем, але останнім часом тримався. Свідки кажуть, що він дуже змінився після сварки з жертвою.', '/suspects/william.jpg'),
('a1b2c3d4-0004-4000-8000-000000000004', 'Sophia', 'Williams', 'female', 41, 'Lawyer', 'Gardening', 'Gossiping', 39, 'Blonde', 'Софія Вільямс — успішна адвокатка з власною практикою. Спеціалізується на кримінальних справах і має репутацію людини, яка ніколи не програє. Відома тим, що йде до кінця і не зупиняється перед тиском. Мала таємні стосунки з жертвою протягом кількох місяців; після розриву залишилися невирішені фінансові та емоційні питання. У саді проводить багато часу — каже, що це допомагає зняти стрес.', '/suspects/sophia.jpg'),
('a1b2c3d4-0005-4000-8000-000000000005', 'Michael', 'Jones', 'male', 45, 'Teacher', 'Hiking', 'Procrastination', 43, 'Brown', 'Майкл Джонс викладає історію в школі вже двадцять років. Тихий і замкнутий, учні його поважають, але не всі колеги його люблять. Колись був звинувачений у крадіжці коштів шкільної каси, але справу закрили через недостатність доказів. Тримає глибоку злість на жертву, яка, за його словами, зруйнувала йому життя. У вільний час ходить у походи та збирає книги з історії.', '/suspects/michael.jpg'),
('a1b2c3d4-0006-4000-8000-000000000006', 'Emma', 'Brown', 'female', 33, 'Artist', 'Painting', 'Overeating', 37, 'Brown', 'Емма Браун — художниця, працює з олією, акрилом та скульптурою. Щодня використовує різальні інструменти, ножі та молотки в майстерні. Жертва, відомий критик, відмовив їй у виставці та публічно розкритикував її роботи. Після цього Емма публічно погрожувала йому в соцмережах. Кілька свідків бачили її неподалік місця події того вечора. Вона заперечує звинувачення.', '/suspects/emma.jpg'),
('a1b2c3d4-0007-4000-8000-000000000007', 'James', 'Davis', 'male', 38, 'Programmer', 'Gaming', 'Oversleeping', 41, 'Blonde', 'Джеймс Дейвіс — програміст, працює віддалено на великий tech-проєкт. Мав повний доступ до особистих даних та листування жертви через спільний корпоративний проєкт. Дуже ревнував до успіху жертви, який часто хвалили на зустрічах. Колеги пригадують його скарги та згадки про те, що хтось "займає його місце". У нього немає алібі на час вбивства — каже, що спав вдома.', '/suspects/james.jpg'),
('a1b2c3d4-0008-4000-8000-000000000008', 'Isabella', 'Miller', 'female', 29, 'Nurse', 'Knitting', 'Skipping Meals', 36, 'Brown', 'Ізабелла Міллер — медсестра в лікарні, працює в відділенні інтенсивної терапії. Добре знає, як використовувати ліки, інъекції та отруйні речовини в медичних дозах. Жертва була пацієнтом її відділення кілька років тому; є непідтверджені скарги на неї від родичів інших пацієнтів. Брат Ізабелли помер через кілька років після виписки — родина звинувачувала лікарню та пов’язувала це з жертвою.', '/suspects/isabella.jpg'),
('a1b2c3d4-0009-4000-8000-000000000009', 'Alexander', 'Wilson', 'male', 55, 'Scientist', 'Collecting', 'Swearing', 45, 'Brown', 'Олександр Вільсон — вчений-хімік, керує лабораторією при університеті. Має повний доступ до небезпечних речовин та складів. Довгі роки суперничав з жертвою за гранти та публікації; останній раз вони гостро сварились на конференції перед усіма. Колеги описують їхні стосунки як "відкриту ворожнечу". Олександр заперечує будь-яку причетність і називає звинувачення абсурдними.', '/suspects/alexander.jpg'),
('a1b2c3d4-0010-4000-8000-000000000010', 'Ava', 'Taylor', 'female', 36, 'Writer', 'Traveling', 'Watching Too Much TV', 38, 'Blonde', 'Ава Тейлор — письменниця детективних романів, авторка кількох бестселерів. Добре знає криміналістику та психологію злочинців з досліджень для книг. Жертва публічно звинувачував її в плагіаті та опублікував уривки, схожі на її неопублікований рукопис. Справа не дійшла до суду, але Ава публічно обіцяла "відповісти по-своєму". Вона часто подорожує і має нестабільний графік.', '/suspects/ava.jpg'),
('a1b2c3d4-0011-4000-8000-000000000011', 'Victor', 'Reed', 'male', 48, 'Gardener', 'Gardening', 'Smoking', 43, 'Brown', 'Віктор Рід — садівник у маєтку вже п’ятнадцять років. Щодня працює з лопатою, мотикою та садовим інвентарем. Жертва планувала знести старий сарай і вирубати дерева, які Віктор вирощував роками. Вони кілька разів сварились на території; остання сутичка була за тиждень до події. Сусіди кажуть, що Віктор дуже прив’язаний до саду і не раз погрожував "захистити його".', '/suspects/victor.jpg'),
('a1b2c3d4-0012-4000-8000-000000000012', 'Maria', 'Santos', 'female', 31, 'Pharmacist', 'Reading', 'Coffee addiction', 37, 'Brown', 'Марія Сантос — провізорка в аптеці на головній вулиці. Має доступ до ліків, отрут та рецептурних препаратів. Жертва колишній керівник, який звинуватив її в помилці в рецепті — через це Марія ледь не втратила ліцензію. Вона заперечувала звинувачення і казала, що це він підробив документи. Того дня вона залишалась після закриття, щоб "перевірити склад".', '/suspects/maria.jpg'),
('a1b2c3d4-0013-4000-8000-000000000013', 'David', 'Black', 'male', 39, 'Security guard', 'Fishing', 'Gambling', 44, 'Brown', 'Девід Блек — охоронець у торговому центрі, раніше служив у поліції. Знає, як поводитись у конфліктах і має доступ до записів камер. Жертва був його старим знайомим по службі; Девід звинувачував його в тому, що той здав його під час внутрішнього розслідування. Останнім часом мав фінансові проблеми через гральний борг. Той вечір він був на чергуванні неподалік.', '/suspects/david.jpg'),
('a1b2c3d4-0014-4000-8000-000000000014', 'Nina', 'Petrov', 'female', 44, 'Veterinarian', 'Horse riding', 'Workaholic', 39, 'Brown', 'Ніна Петрова — ветеринарка з власною клінікою. Щодня працює з анестетиками, сильнодіючими препаратами та хімікатами. Жертва інвестував у її клініку, потім вимагав повернення грошей з відсотками і погрожував судом. Ніна казала, що він навмисно затягував документи. Кілька клієнтів бачили їхню сварку в приймальні. Вона заперечує причетність.', '/suspects/nina.jpg'),
('a1b2c3d4-0015-4000-8000-000000000015', 'Thomas', 'Wright', 'male', 58, 'Carpenter', 'Woodworking', 'Drinking', 45, 'Brown', 'Томас Райт — столяр, має майстерню на околиці міста. Працює з молотком, долотом, пилками щодня. Жертва замовив у нього меблі, заплатив аванс, потім відмовився забирати і вимагав гроші назад. Томас відмовляв — робота була зроблена. Суд затягувався; жертва публічно називав його шахраєм. Того дня Томас каже, що був один у майстерні і пив.', '/suspects/thomas.jpg'),
('a1b2c3d4-0016-4000-8000-000000000016', 'Laura', 'Chen', 'female', 27, 'Journalist', 'Running', 'Perfectionism', 36, 'Black', 'Лора Чен — журналістка, пише про кримінал та суди. Вела розслідування про жертву кілька років тому; стаття не вийшла через тиск. Вона зберігала матеріали і казала, що "колись це стане в нагоді". Той день вона інтерв’ювала свідка неподалік. Лора заперечує звинувачення і каже, що їй вигідніше було б тримати його живим — для матеріалу.', '/suspects/laura.jpg'),
('a1b2c3d4-0017-4000-8000-000000000017', 'Richard', 'Moore', 'male', 62, 'Retired soldier', 'Hunting', 'Anger issues', 46, 'Brown', 'Річард Мур — у відставці, двадцять років служив у армії. Вміє поводитись зі зброєю та діяти в екстремальних ситуаціях. Жертва був його командиром; Річард звинувачував його в тому, що той залишив їхній підрозділ без підтримки — загинули люди. Він ніколи не приховував ненависть. Того вечора був у барі, каже — випив і пішов. Свідки пам’ятають його агресивну поведінку.', '/suspects/richard.jpg'),
('a1b2c3d4-0018-4000-8000-000000000018', 'Elena', 'Vasquez', 'female', 35, 'Bartender', 'Dancing', 'Gossiping', 38, 'Brown', 'Елена Васкес — барменка в клубі "Нічний порт". Працює там п’ять років, знає постійних гостей і їхні звички. Жертва часто приходив і залишав великі чайові; вони спілкувались. Останнім часом він перестав платити за напої і почав погрожувати "рознести репутацію" клубу. Елена каже, що того вечора вона була за барною стійкою і нічого підозрілого не бачила.', '/suspects/elena.jpg');
INSERT INTO cases (id, intro_text, body_location, tool_description, evidence_description, difficulty, killer_id, motive, confession_text) VALUES
('c1d2e3f4-0001-4000-8000-000000000001',
INSERT INTO case_suspects (case_id, suspect_id, testimony_text, is_killer) VALUES
('c1d2e3f4-0001-4000-8000-000000000001', 'a1b2c3d4-0003-4000-8000-000000000003', 'Я заходив у бібліотеку того вечора — він кликав мене "поговорити". Ми сперечались про гроші. Я палю, отже сліди тютюну можуть бути моїми. Пішов у лють, не пам''ятаю деталей.', true),
('c1d2e3f4-0001-4000-8000-000000000001', 'a1b2c3d4-0001-4000-8000-000000000001', 'У мене 42 розмір, у бібліотеці того вечора не був. Сидів у кімнаті, читав. Фінансово мені теж було нелегко, але з жертвою не сварився.', false),
('c1d2e3f4-0001-4000-8000-000000000001', 'a1b2c3d4-0002-4000-8000-000000000002', 'Я лікарка. Смерть настала швидко від удару. Мій розмір взуття 38, у бібліотеці того дня не була — була на виклику.', false);
INSERT INTO cases (id, intro_text, body_location, tool_description, evidence_description, difficulty, killer_id, motive, confession_text) VALUES
('c1d2e3f4-0002-4000-8000-000000000002',
INSERT INTO case_suspects (case_id, suspect_id, testimony_text, is_killer) VALUES
('c1d2e3f4-0002-4000-8000-000000000002', 'a1b2c3d4-0008-4000-8000-000000000008', 'Я була поруч із його столиком — він скаржився на головний біль. Я сказала, що це може бути тиск, і запропонувала воду. Платок мій; я могла торкнутися келиха. Я не хочу більше нічого говорити.', true),
('c1d2e3f4-0002-4000-8000-000000000002', 'a1b2c3d4-0004-4000-8000-000000000004', 'Я була з клієнтом у іншій кімнаті до 22:30. До столика жертви не підходила. Не знаю, хто мав доступ до його напою.', false),
('c1d2e3f4-0002-4000-8000-000000000002', 'a1b2c3d4-0005-4000-8000-000000000005', 'Я пив вино в іншому кутку. З жертвою не спілкувався. О 21:45 бачив біля нього жінку — не знаю, хто це.', false),
('c1d2e3f4-0002-4000-8000-000000000002', 'a1b2c3d4-0009-4000-8000-000000000009', 'Я хімік, речовину таку отримати можу. Але того вечора я не підходив до його столу і з ним не розмовляв. Перевірте, хто мав особистий мотив.', false);
INSERT INTO cases (id, intro_text, body_location, tool_description, evidence_description, difficulty, killer_id, motive, confession_text) VALUES
('c1d2e3f4-0003-4000-8000-000000000003',
INSERT INTO case_suspects (case_id, suspect_id, testimony_text, is_killer) VALUES
('c1d2e3f4-0003-4000-8000-000000000003', 'a1b2c3d4-0006-4000-8000-000000000006', 'Я була в студії того дня — він приїхав на перегляд. Ми сварились; я працювала над полотном, тому фарба на мені. Ніготь зламала вже пізніше, коли нервувала. Більше не коментую.', true),
('c1d2e3f4-0003-4000-8000-000000000003', 'a1b2c3d4-0007-4000-8000-000000000007', 'Я не художник і в студії не був. Алібі — я був вдома, онлайн. З жертвою мав конфлікт через роботу, але не фізично.', false),
('c1d2e3f4-0003-4000-8000-000000000003', 'a1b2c3d4-0010-4000-8000-000000000010', 'Я письменниця, інтерв’ювала його колись. Того дня була в бібліотеці. До студії не заходила; з ним теж був конфлікт через плагіат.', false);
INSERT INTO cases (id, intro_text, body_location, tool_description, evidence_description, difficulty, killer_id, motive, confession_text) VALUES
('c1d2e3f4-0004-4000-8000-000000000004',
INSERT INTO case_suspects (case_id, suspect_id, testimony_text, is_killer) VALUES
('c1d2e3f4-0004-4000-8000-000000000004', 'a1b2c3d4-0011-4000-8000-000000000011', 'Я був у саду того дня, у мене 43 розмір. Ми сварились біля сараю — він сказав, що все піде під знесення. Рукавиця могла бути моя; сліди теж. Я там щодня.', true),
('c1d2e3f4-0004-4000-8000-000000000004', 'a1b2c3d4-0005-4000-8000-000000000005', 'У мене 43 розмір, але я викладач. У маєтку був на екскурсії тиждень тому. Того дня вдома. В саду не був.', false),
('c1d2e3f4-0004-4000-8000-000000000004', 'a1b2c3d4-0004-4000-8000-000000000004', 'Я адвокат маєтку. Того дня була в місті на зустрічі. Розмір взуття 39. У сараї не була.', false),
('c1d2e3f4-0004-4000-8000-000000000004', 'a1b2c3d4-0013-4000-8000-000000000013', 'Я охоронець у торговому центрі. Розмір 44. Маєток не охороняю, у саду не був.', false);
INSERT INTO cases (id, intro_text, body_location, tool_description, evidence_description, difficulty, killer_id, motive, confession_text) VALUES
('c1d2e3f4-0005-4000-8000-000000000005',
INSERT INTO case_suspects (case_id, suspect_id, testimony_text, is_killer) VALUES
('c1d2e3f4-0005-4000-8000-000000000005', 'a1b2c3d4-0012-4000-8000-000000000012', 'Я залишалась після закриття — перевіряла склад. Він прийшов без запису, сказав "треба поговорити". Я була з ним у задній кімнаті одна. Шприц і флакон з нашої аптеки. Мотив... перевірте мою біографію.', true),
('c1d2e3f4-0005-4000-8000-000000000005', 'a1b2c3d4-0009-4000-8000-000000000009', 'Я хімік, таку речовину отримати можу. Але того вечора я був у лабораторії — є запис. До аптеки не заходив. Хто мав особистий конфлікт із жертвою?', false),
('c1d2e3f4-0005-4000-8000-000000000005', 'a1b2c3d4-0008-4000-8000-000000000008', 'Я медсестра в лікарні. У тій аптеці не працюю і в задній кімнаті не була. Перевірте, хто там фактично був того вечора.', false),
('c1d2e3f4-0005-4000-8000-000000000005', 'a1b2c3d4-0001-4000-8000-000000000001', 'Я купував ліки там тиждень тому. Того дня не виходив з дому — працював віддалено. З жертвою не знайомий.', false);
INSERT INTO cases (id, intro_text, body_location, tool_description, evidence_description, difficulty, killer_id, motive, confession_text) VALUES
('c1d2e3f4-0006-4000-8000-000000000006',
INSERT INTO case_suspects (case_id, suspect_id, testimony_text, is_killer) VALUES
('c1d2e3f4-0006-4000-8000-000000000006', 'a1b2c3d4-0015-4000-8000-000000000015', 'Він прийшов того вечора. Ми сварились через гроші. У мене 45 розмір; молоток мій. Я залишив сліди. Мотив — перевірте мою біографію, наш конфлікт.', true),
('c1d2e3f4-0006-4000-8000-000000000006', 'a1b2c3d4-0007-4000-8000-000000000007', 'Я програміст. У майстерні не був. Розмір 41. Алібі — вдома один. З жертвою конфлікт через роботу, не через меблі.', false),
('c1d2e3f4-0006-4000-8000-000000000006', 'a1b2c3d4-0006-4000-8000-000000000006', 'Я художниця, 37 розмір. Столярню не відвідую. Той день була в галереї. З жертвою інший конфлікт — не меблі.', false),
('c1d2e3f4-0006-4000-8000-000000000006', 'a1b2c3d4-0017-4000-8000-000000000017', 'У мене 46 розмір. Майстерні не маю, того чоловіка не знаю. Перевірте, хто мав з ним справу через гроші.', false);
INSERT INTO cases (id, intro_text, body_location, tool_description, evidence_description, difficulty, killer_id, motive, confession_text) VALUES
('c1d2e3f4-0007-4000-8000-000000000007',
INSERT INTO case_suspects (case_id, suspect_id, testimony_text, is_killer) VALUES
('c1d2e3f4-0007-4000-8000-000000000007', 'a1b2c3d4-0017-4000-8000-000000000017', 'Я був у барі. Ми сварились — він дражнив мене. Я вийшов за ним у алею. Жетон мій, я його втратив там. Пляшка була в руках. Перевірте мою біографію — з ним у мене була особиста справа.', true),
('c1d2e3f4-0007-4000-8000-000000000007', 'a1b2c3d4-0018-4000-8000-000000000018', 'Я барменка. Бачила, як вони вийшли разом. Через кілька хвилин почула крики. Викликала поліцію. Хто з них що зробив — не бачила.', false),
('c1d2e3f4-0007-4000-8000-000000000007', 'a1b2c3d4-0013-4000-8000-000000000013', 'Я був у барі як відвідувач. Бачив двох чоловіків у сварці. Не втручався. Жетон не мій. Пішов перед північчю.', false),
('c1d2e3f4-0007-4000-8000-000000000007', 'a1b2c3d4-0001-4000-8000-000000000001', 'Я був у барі з колегами. Виходив на перекур — у алею не заходив. З жертвою не знайомий.', false),
('c1d2e3f4-0007-4000-8000-000000000007', 'a1b2c3d4-0010-4000-8000-000000000010', 'Збирала матеріал для роману. Бачила сварку. Не підходила. Особистого мотиву з жертвою не мала — тільки публічний конфлікт через плагіат.', false);
INSERT INTO cases (id, intro_text, body_location, tool_description, evidence_description, difficulty, killer_id, motive, confession_text) VALUES
('c1d2e3f4-0008-4000-8000-000000000008',
INSERT INTO case_suspects (case_id, suspect_id, testimony_text, is_killer) VALUES
('c1d2e3f4-0008-4000-8000-000000000008', 'a1b2c3d4-0014-4000-8000-000000000014', 'Я була в клініці того вечора одна. Він прийшов без запису — "підписати документи". Я приймала його у процедурній. Журнал і шприц з моєї зони. Мотив — перевірте мою біографію, наш конфлікт через гроші.', true),
('c1d2e3f4-0008-4000-8000-000000000008', 'a1b2c3d4-0002-4000-8000-000000000002', 'Я лікарка для людей. У ветеринарній клініці не працюю і того дня не була. Речовину таку отримати можу теоретично, але доступу до їхньої процедурної не мала.', false),
('c1d2e3f4-0008-4000-8000-000000000008', 'a1b2c3d4-0009-4000-8000-000000000009', 'Я хімік, інші речовини. До ветеринарної клініки не маю відношення. Хто мав доступ до процедурної і особистий конфлікт із інвестором?', false),
('c1d2e3f4-0008-4000-8000-000000000008', 'a1b2c3d4-0016-4000-8000-000000000016', 'Журналістка. Інтерв’ювала працівників клініки тиждень тому. Того дня була в редакції. До процедурної не заходила.', false);
